import {
  Action,
  ActionPanel,
  Color,
  Icon,
  List,
  Toast,
  getPreferenceValues,
  showToast
} from "@raycast/api";
import { useEffect, useMemo, useState } from "react";
import { loadChannels } from "./channel-loader";
import { loadHistory, recordSelection, setFavorite } from "./history-store";
import { openDiscordUrl } from "./launcher";
import { rankChannels } from "./search-engine";
import { DiscordChannel, HistoryState, RankedChannel, SearchFilter } from "./types";

type Preferences = {
  channelsPath?: string;
};

const filters: { id: SearchFilter; title: string }[] = [
  { id: "all", title: "All" },
  { id: "dms", title: "DMs" },
  { id: "servers", title: "Servers" },
  { id: "threads", title: "Threads" },
  { id: "favorites", title: "Favorites" },
  { id: "recent", title: "Recent" }
];

export default function Command() {
  const preferences = getPreferenceValues<Preferences>();
  const [channels, setChannels] = useState<DiscordChannel[]>([]);
  const [historyState, setHistoryState] = useState<HistoryState>({ history: {} });
  const [query, setQuery] = useState("");
  const [filter, setFilter] = useState<SearchFilter>("all");
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string>();

  useEffect(() => {
    let canceled = false;

    async function bootstrap() {
      try {
        const loadedChannels = loadChannels(preferences.channelsPath || "~/channels.json");
        const loadedHistory = await loadHistory();
        if (!canceled) {
          setChannels(loadedChannels);
          setHistoryState(loadedHistory);
        }
      } catch (unknownError) {
        if (!canceled) setError(unknownError instanceof Error ? unknownError.message : String(unknownError));
      } finally {
        if (!canceled) setIsLoading(false);
      }
    }

    bootstrap();
    return () => {
      canceled = true;
    };
  }, [preferences.channelsPath]);

  const rankedChannels = useMemo(
    () => rankChannels(query, channels, historyState, filter, 200),
    [channels, filter, historyState, query]
  );

  if (error) {
    return (
      <List filtering={false} searchText={query} onSearchTextChange={setQuery}>
        <List.EmptyView icon={Icon.Warning} title="Unable to Load Channels" description={error} />
      </List>
    );
  }

  return (
    <List
      isLoading={isLoading}
      filtering={false}
      searchText={query}
      onSearchTextChange={setQuery}
      searchBarPlaceholder="Search Discord"
      searchBarAccessory={
        <List.Dropdown tooltip="Filter" value={filter} onChange={(value) => setFilter(value as SearchFilter)}>
          {filters.map((item) => (
            <List.Dropdown.Item key={item.id} title={item.title} value={item.id} />
          ))}
        </List.Dropdown>
      }
    >
      {rankedChannels.map((channel) => (
        <ChannelItem
          key={channel.channelId}
          channel={channel}
          historyState={historyState}
          onHistoryChange={setHistoryState}
        />
      ))}
      {!isLoading && rankedChannels.length === 0 ? (
        <List.EmptyView icon={Icon.MagnifyingGlass} title="No Discord Channels Found" />
      ) : null}
    </List>
  );
}

function ChannelItem({
  channel,
  historyState,
  onHistoryChange
}: {
  channel: RankedChannel;
  historyState: HistoryState;
  onHistoryChange: (state: HistoryState) => void;
}) {
  const isFavorite = channel.history?.favorite === true;

  async function openChannel() {
    try {
      await openDiscordUrl(channel.url);
      onHistoryChange(await recordSelection(historyState, channel.channelId));
    } catch (error) {
      await showToast({
        style: Toast.Style.Failure,
        title: "Could not open Discord",
        message: error instanceof Error ? error.message : String(error)
      });
    }
  }

  async function toggleFavorite() {
    onHistoryChange(await setFavorite(historyState, channel.channelId, !isFavorite));
  }

  return (
    <List.Item
      icon={iconForKind(channel.kind)}
      title={channel.displayName}
      subtitle={subtitleForChannel(channel)}
      accessories={accessoriesForChannel(channel)}
      actions={
        <ActionPanel>
          <Action title="Open in Discord" icon={Icon.ArrowRight} onAction={openChannel} />
          <Action
            title={isFavorite ? "Remove Favorite" : "Add Favorite"}
            icon={isFavorite ? Icon.StarDisabled : Icon.Star}
            shortcut={{ modifiers: ["cmd"], key: "f" }}
            onAction={toggleFavorite}
          />
          <Action.CopyToClipboard
            title="Copy Discord URL"
            content={channel.url}
            shortcut={{ modifiers: ["shift"], key: "enter" }}
          />
          <Action.CopyToClipboard
            title="Copy Channel ID"
            content={channel.channelId}
            shortcut={{ modifiers: ["opt"], key: "enter" }}
          />
        </ActionPanel>
      }
    />
  );
}

function subtitleForChannel(channel: DiscordChannel): string {
  return [labelForKind(channel.kind), channel.serverTag, channel.username].filter(Boolean).join(" • ");
}

function accessoriesForChannel(channel: RankedChannel): List.Item.Accessory[] {
  const accessories: List.Item.Accessory[] = [];
  if (channel.history?.favorite) accessories.push({ text: "Favorite", icon: { source: Icon.Star, tintColor: Color.Yellow } });
  if (channel.history?.lastOpened) accessories.push({ date: new Date(channel.history.lastOpened) });
  accessories.push({ tag: labelForKind(channel.kind) });
  return accessories;
}

function iconForKind(kind: DiscordChannel["kind"]): List.Item.Props["icon"] {
  switch (kind) {
    case "dm":
      return Icon.Person;
    case "group":
      return Icon.TwoPeople;
    case "guild":
      return Icon.Building;
    case "thread":
      return Icon.SpeechBubble;
    case "voice":
      return Icon.Microphone;
    case "forum":
      return Icon.TextDocument;
    default:
      return Icon.Hashtag;
  }
}

function labelForKind(kind: DiscordChannel["kind"]): string {
  switch (kind) {
    case "dm":
      return "DM";
    case "group":
      return "Group";
    case "guild":
      return "Server";
    case "thread":
      return "Thread";
    case "voice":
      return "Voice";
    case "forum":
      return "Forum";
    default:
      return "Channel";
  }
}
