import { recencyScore } from "./history-store";
import { DiscordChannel, HistoryState, RankedChannel, SearchFilter } from "./types";

const favoriteBonus = 900;
const recentThresholdMs = 30 * 24 * 60 * 60 * 1000;

export function rankChannels(
  query: string,
  channels: DiscordChannel[],
  historyState: HistoryState,
  filter: SearchFilter = "all",
  limit = 100
): RankedChannel[] {
  const normalizedQuery = normalize(query);
  const queryTokens = tokenize(normalizedQuery);
  const now = Date.now();

  return channels
    .map((channel) => {
      const history = historyState.history[channel.channelId];
      return { ...channel, history, score: scoreChannel(channel, normalizedQuery, queryTokens, historyState, now) };
    })
    .filter((channel) => matchesFilter(channel, filter, now))
    .filter((channel) => !channel.history?.hidden)
    .filter((channel) => normalizedQuery.length > 0 || wasPreviouslyOpened(channel))
    .filter((channel) => normalizedQuery.length === 0 || channel.score > 0)
    .sort((a, b) => b.score - a.score || a.displayName.localeCompare(b.displayName))
    .slice(0, limit);
}

function wasPreviouslyOpened(channel: RankedChannel): boolean {
  return Boolean(channel.history?.lastOpened || channel.history?.count);
}

function scoreChannel(
  channel: DiscordChannel,
  query: string,
  queryTokens: string[],
  historyState: HistoryState,
  now: number
): number {
  const history = historyState.history[channel.channelId];
  const haystack = normalize(channel.search);
  const displayName = normalize(channel.displayName);
  const tokens = tokenize(haystack);

  let score = query ? 0 : 50;

  if (query) {
    if (displayName === query || haystack === query) score += 10_000;
    if (displayName.startsWith(query)) score += 8_000;
    if (haystack.startsWith(query)) score += 6_000;
    if (tokens.some((token) => token.startsWith(query))) score += 4_500;
    if (haystack.includes(query)) score += 2_000;
    if (acronym(tokens).startsWith(query)) score += 1_600;
    score += queryTokens.every((token) => tokens.some((searchToken) => searchToken.startsWith(token))) ? 1_200 : 0;
    score += fuzzyScore(query, haystack);
  }

  score += recencyScore(history, now) * 300;
  if (history?.favorite) score += favoriteBonus;
  score -= Math.min(displayName.length, 80) * 3;

  return score;
}

function matchesFilter(channel: RankedChannel, filter: SearchFilter, now: number): boolean {
  switch (filter) {
    case "dms":
      return channel.kind === "dm" || channel.kind === "group";
    case "servers":
      return channel.kind === "guild" || channel.kind === "channel" || channel.kind === "voice" || channel.kind === "forum";
    case "threads":
      return channel.kind === "thread";
    case "favorites":
      return channel.history?.favorite === true;
    case "recent":
      return Boolean(channel.history?.lastOpened && now - channel.history.lastOpened < recentThresholdMs);
    default:
      return true;
  }
}

function fuzzyScore(query: string, text: string): number {
  let queryIndex = 0;
  let score = 0;
  let streak = 0;

  for (let textIndex = 0; textIndex < text.length && queryIndex < query.length; textIndex += 1) {
    if (text[textIndex] !== query[queryIndex]) {
      streak = 0;
      continue;
    }

    score += 120 + streak * 80;
    if (textIndex === 0 || text[textIndex - 1] === " ") score += 120;
    streak += 1;
    queryIndex += 1;
  }

  return queryIndex === query.length ? score : 0;
}

function normalize(value: string): string {
  return value.toLowerCase().trim();
}

function tokenize(value: string): string[] {
  return value.split(/[^a-z0-9_#!]+/).filter(Boolean);
}

function acronym(tokens: string[]): string {
  return tokens.map((token) => token[0]).join("");
}
