import { LocalStorage } from "@raycast/api";
import { ChannelHistory, HistoryState } from "./types";

const storageKey = "discord-quick-switcher-history";
const halfLifeDays = 21;

export async function loadHistory(): Promise<HistoryState> {
  const stored = await LocalStorage.getItem<string>(storageKey);
  if (!stored) {
    return { history: {} };
  }

  try {
    const parsed = JSON.parse(stored) as HistoryState;
    return { history: parsed.history ?? {} };
  } catch {
    return { history: {} };
  }
}

export async function recordSelection(state: HistoryState, channelId: string): Promise<HistoryState> {
  const now = Date.now();
  const previous = state.history[channelId];
  const next: ChannelHistory = {
    count: (previous?.count ?? 0) + 1,
    lastOpened: now,
    rollingScore: decayedScore(previous, now) + 1,
    favorite: previous?.favorite ?? false,
    hidden: previous?.hidden
  };

  const nextState = { history: { ...state.history, [channelId]: next } };
  await saveHistory(nextState);
  return nextState;
}

export async function setFavorite(state: HistoryState, channelId: string, favorite: boolean): Promise<HistoryState> {
  const previous = state.history[channelId];
  const nextState = {
    history: {
      ...state.history,
      [channelId]: {
        count: previous?.count ?? 0,
        lastOpened: previous?.lastOpened ?? 0,
        rollingScore: previous?.rollingScore ?? 0,
        hidden: previous?.hidden,
        favorite
      }
    }
  };

  await saveHistory(nextState);
  return nextState;
}

export function recencyScore(history: ChannelHistory | undefined, now = Date.now()): number {
  return decayedScore(history, now);
}

async function saveHistory(state: HistoryState): Promise<void> {
  await LocalStorage.setItem(storageKey, JSON.stringify(state));
}

function decayedScore(history: ChannelHistory | undefined, now: number): number {
  if (!history?.lastOpened) {
    return 0;
  }

  const ageDays = Math.max(0, now - history.lastOpened) / 86_400_000;
  return (history.rollingScore || history.count || 0) * Math.pow(0.5, ageDays / halfLifeDays);
}
