export const channelKinds = ["dm", "group", "guild", "channel", "thread", "voice", "forum"] as const;

export type ChannelKind = (typeof channelKinds)[number];

export type DiscordChannel = {
  kind: ChannelKind;
  channelId: string;
  userId: string | null;
  displayName: string;
  username: string | null;
  serverTag: string | null;
  serverId: string | null;
  search: string;
  url: string;
};

export type ChannelHistory = {
  count: number;
  lastOpened: number;
  rollingScore: number;
  favorite: boolean;
  hidden?: boolean;
};

export type HistoryState = {
  history: Record<string, ChannelHistory>;
};

export type SearchFilter = "all" | "dms" | "servers" | "threads" | "favorites" | "recent";

export type RankedChannel = DiscordChannel & {
  score: number;
  history?: ChannelHistory;
};
